pub(crate) fn serialize_surface_style_fill_area(
    buf: &mut crate::writer::buffer::WriteBuffer,
    l1: &super::model::EarlySurfaceStyleFillArea,
) -> u64 {
    buf.push_simple(
        "SURFACE_STYLE_FILL_AREA",
        vec![crate::parser::entity::Attribute::EntityRef(l1.fill_area)],
    )
}

pub(crate) fn serialize_view_volume(
    buf: &mut crate::writer::buffer::WriteBuffer,
    l1: &super::model::EarlyViewVolume,
) -> u64 {
    buf.push_simple(
        "VIEW_VOLUME",
        vec![
            central_or_parallel_attr(l1.projection_type),
            crate::parser::entity::Attribute::EntityRef(l1.projection_point),
            crate::parser::entity::Attribute::Real(l1.view_plane_distance),
            crate::parser::entity::Attribute::Real(l1.front_plane_distance),
            bool_attr(l1.front_plane_clipping),
            crate::parser::entity::Attribute::Real(l1.back_plane_distance),
            bool_attr(l1.back_plane_clipping),
            bool_attr(l1.view_volume_sides_clipping),
            crate::parser::entity::Attribute::EntityRef(l1.view_window),
        ],
    )
}

fn central_or_parallel_attr(
    v: crate::ir::visualization::Projection,
) -> crate::parser::entity::Attribute {
    crate::parser::entity::Attribute::Enum(
        match v {
            crate::ir::visualization::Projection::Central => "CENTRAL",
            crate::ir::visualization::Projection::Parallel => "PARALLEL",
        }
        .into(),
    )
}

fn bool_attr(b: bool) -> crate::parser::entity::Attribute {
    crate::parser::entity::Attribute::Enum(if b { "T" } else { "F" }.into())
}
